index f9155cc66031..b5b35840ed8c 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2719,6 +2719,7 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   // Note: We don't generate the inverse max/min, just create the 'not' of
   // it and let other folds do the rest.
   if (match(Op0, m_Not(m_Value(X))) &&
+
       match(Op1, m_c_MaxOrMin(m_Specific(Op0), m_Value(Y))) &&
       !Op0->hasNUsesOrMore(3) && isFreeToInvert(Y, Y->hasOneUse())) {
     Value *Not = Builder.CreateNot(Op1);
@@ -2834,6 +2835,31 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     return BinaryOperator::CreateNeg(USub);
   }

+  // smin(X + 1, Y) - smin(X, Y) --> X < Y ? 1 : 0
+  {
+    Value *SmallerX, *Bound, *Inc;
+    if (match(Op1, m_c_SMin(m_Value(SmallerX), m_Value(Bound))) &&
+        match(Op0, m_c_SMin(m_Value(Inc), m_Specific(Bound)))) {
+      auto HasNUWNSWAddOfOne = [&](Value *V) {
+        Value *AddX;
+        if (!(match(V, m_Add(m_Value(AddX), m_One())) ||
+              match(V, m_Add(m_One(), m_Value(AddX)))))
+          return false;
+        if (AddX != SmallerX)
+          return false;
+        auto *OBO = dyn_cast<OverflowingBinaryOperator>(V);
+        return OBO && OBO->hasNoUnsignedWrap() && OBO->hasNoSignedWrap();
+      };
+
+      if (HasNUWNSWAddOfOne(Inc)) {
+        Value *Cmp = Builder.CreateICmpSLT(SmallerX, Bound);
+        Value *One = ConstantInt::get(Ty, 1);
+        Value *Zero = ConstantInt::getNullValue(Ty);
+        return SelectInst::Create(Cmp, One, Zero);
+      }
+    }
+  }
+
   // C - ctpop(X) => ctpop(~X) if C is bitwidth
   if (match(Op0, m_SpecificInt(BitWidth)) &&
       match(Op1, m_OneUse(m_Intrinsic<Intrinsic::ctpop>(m_Value(X)))))
@@ -2920,6 +2946,7 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   return TryToNarrowDeduceFlags();
 }

+
 /// This eliminates floating-point negation in either 'fneg(X)' or
 /// 'fsub(-0.0, X)' form by combining into a constant operand.
 static Instruction *foldFNegIntoConstant(Instruction &I, const DataLayout &DL) {

